def compare_substring_match(spans_a, spans_b):
    """
    Story Hero / Protagonist — flexible text matching.
    Exact Match if:
      - same label AND
      - one text is contained in the other (case-insensitive, whitespace-normalised)
    """
    def norm(s):
        return re.sub(r"\s+", " ", s.strip()).lower()

    results = []
    used_b  = set()

    for sa in spans_a:
        matched = False
        ta = norm(sa["text"])
        for i, sb in enumerate(spans_b):
            if i in used_b:
                continue
            if sa["label"] != sb["label"]:
                continue
            tb = norm(sb["text"])
            if not ta or not tb:
                continue

            if ta == tb:
                status = "Exact Match"
            elif ta in tb or tb in ta:
                status = "Exact Match (substring)"
            else:
                continue

            results.append({
                "My Text"      : sa["text"],
                "My Label"     : sa["label"],
                "Ann Text"     : sb["text"],
                "Ann Label"    : sb["label"],
                "Match Status" : status,
            })
            used_b.add(i)
            matched = True
            break

        if not matched:
            results.append({
                "My Text"      : sa["text"],
                "My Label"     : sa["label"],
                "Ann Text"     : "",
                "Ann Label"    : "",
                "Match Status" : "Only Me",
            })

    for i, sb in enumerate(spans_b):
        if i not in used_b:
            results.append({
                "My Text"      : "",
                "My Label"     : "",
                "Ann Text"     : sb["text"],
                "Ann Label"    : sb["label"],
                "Match Status" : "Only Annotator",
            })

    return results

