    # per-title delta vs Human
    wide = (paired.pivot_table(index="StoryID", columns="Source",
                               values=METRIC_COLS))
    delta_rows = []
    for sid_ in human_ids:
        if sid_ not in wide.index:
            continue
        for col in METRIC_COLS:
            try:
                h = wide.loc[sid_, (col, "Human")]
