                    "Metric":  col,
                    "Model":   model,
                    "Human":   round(h, 3),
                    "Model":   model,
                    "Model_Value": round(v, 3),
                    "Delta":   round(v - h, 3),
                })
    per_title_deltas = pd.DataFrame(delta_rows)
    # mean and sign of per-title deltas
